import{_ as a,o,c as e,a3 as l}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"📚 索引引擎","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/knowledge-base/indexing.md","filePath":"user-guide/tools/knowledge-base/indexing.md","lastUpdated":1778221347000}'),r={name:"user-guide/tools/knowledge-base/indexing.md"};function i(n,t,d,s,h,g){return o(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="📚-索引引擎" tabindex="-1">📚 索引引擎 <a class="header-anchor" href="#📚-索引引擎" aria-label="Permalink to &quot;📚 索引引擎&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>索引引擎是知识库的核心——它将文本内容转换为向量，建立语义索引，让搜索不再局限于关键词匹配。你可以把它理解为&quot;为知识建立了一张语义地图&quot;，当用户提问时，系统在这张地图上找到最相关的位置。</p><div class="tip custom-block"><p class="custom-block-title">一句话理解</p><p>向量化就是把&quot;猫&quot;和&quot;猫咪&quot;这样的近义词映射到向量空间中相近的位置，让搜索能理解语义而非字面。</p></div><h3 id="核心流程" tabindex="-1">核心流程 <a class="header-anchor" href="#核心流程" aria-label="Permalink to &quot;核心流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户导入条目 → 计算内容哈希 → 生成向量 → 持久化到磁盘 → 加载到内存索引 → 可被检索</span></span></code></pre></div><ol><li><strong>内容哈希校验</strong>：系统会计算条目的内容哈希（Content Hash）。如果内容没有变化，即使重新触发向量化也会被跳过，避免浪费</li><li><strong>向量生成</strong>：调用配置的 Embedding 模型将文本转换为向量</li><li><strong>向量缓存</strong>：利用 <code>vectorCache</code> 缓存已生成的向量，相同内容不会重复调用 API</li><li><strong>持久化存储</strong>：向量以 <code>{entryId}.vec</code> 文件形式存入按模型隔离的目录</li><li><strong>内存加载</strong>：搜索时后端将向量索引加载至内存，进行实时计算</li></ol><h2 id="索引策略" tabindex="-1">索引策略 <a class="header-anchor" href="#索引策略" aria-label="Permalink to &quot;索引策略&quot;">​</a></h2><h3 id="自动索引-vs-手动索引" tabindex="-1">自动索引 vs 手动索引 <a class="header-anchor" href="#自动索引-vs-手动索引" aria-label="Permalink to &quot;自动索引 vs 手动索引&quot;">​</a></h3><p><strong>自动索引</strong>（推荐）</p><p>在 <strong>设置 &gt; 检索与索引策略</strong> 中开启&quot;自动触发向量化&quot;后：</p><ul><li>新建条目时自动开始向量化</li><li>编辑条目保存后自动重新计算向量</li><li>批量导入时自动处理</li></ul><p><strong>手动索引</strong></p><p>关闭自动索引后，你需要手动控制：</p><ul><li><strong>单条索引</strong>：在条目列表中点击某条目的向量化按钮</li><li><strong>批量索引</strong>：点击 <strong>索引全部待处理条目</strong>，系统会逐个处理未向量化的条目</li><li>手动模式适合需要精细控制资源消耗的场景（如 API 调用次数有限）</li></ul><h3 id="增量索引" tabindex="-1">增量索引 <a class="header-anchor" href="#增量索引" aria-label="Permalink to &quot;增量索引&quot;">​</a></h3><p>系统采用<strong>增量索引</strong>策略——不是每次索引都全量重建，而是只处理变化的内容：</p><ul><li><strong>内容未变</strong>：哈希一致，跳过向量化</li><li><strong>内容改变</strong>：重新生成向量并覆盖旧文件</li><li><strong>新增条目</strong>：仅对新条目进行向量化</li><li><strong>删除条目</strong>：同时清理对应的向量文件</li></ul><p>这种策略大幅减少了重复 API 调用和磁盘 IO。</p><h3 id="索引时的前置处理" tabindex="-1">索引时的前置处理 <a class="header-anchor" href="#索引时的前置处理" aria-label="Permalink to &quot;索引时的前置处理&quot;">​</a></h3><p>在向量化之前，系统会对条目内容进行预处理：</p><ul><li><strong>哈希计算</strong>：为每个条目生成内容哈希，用于变更检测</li><li><strong>Key 提取</strong>：从 Markdown 内容中提取第一个一级标题作为 Key（如果导入时未指定）</li><li><strong>标签提取</strong>：从内容中识别 <code>Tags: xxx</code> 或 <code>标签: xxx</code> 标记自动添加标签</li><li><strong>长度校验</strong>：单个 CAIU 有 12,000 字符的长度限制（可在设置中调整），超出会跳过并记录失败</li></ul><h2 id="嵌入模型配置" tabindex="-1">嵌入模型配置 <a class="header-anchor" href="#嵌入模型配置" aria-label="Permalink to &quot;嵌入模型配置&quot;">​</a></h2><h3 id="选择模型" tabindex="-1">选择模型 <a class="header-anchor" href="#选择模型" aria-label="Permalink to &quot;选择模型&quot;">​</a></h3><p>知识库使用 Embedding 模型来生成向量。选择时建议考虑：</p><ol><li><strong>维度一致性</strong>：同一个知识库建议使用同一维度（Dimension）的模型。切换模型后，旧向量不会自动失效，但新生成的向量会使用新维度</li><li><strong>模型性能</strong>：轻量级模型速度快但语义理解能力弱，大规模模型效果好但速度慢、成本高</li><li><strong>供应商</strong>：支持所有已配置的 LLM 服务供应商</li></ol><blockquote><p>TODO: 截图 - 设置页面中的模型选择器</p></blockquote><h3 id="探测维度" tabindex="-1">探测维度 <a class="header-anchor" href="#探测维度" aria-label="Permalink to &quot;探测维度&quot;">​</a></h3><p>不同 Embedding 模型的输出维度不同（如 OpenAI <code>text-embedding-3-small</code> 为 1536 维，<code>text-embedding-3-large</code> 为 3072 维）。配置后建议点击 <strong>探测模型维度</strong> 按钮，系统会自动调用模型 API 检测其维度并填入配置。</p><h3 id="向量维度配置" tabindex="-1">向量维度配置 <a class="header-anchor" href="#向量维度配置" aria-label="Permalink to &quot;向量维度配置&quot;">​</a></h3><p>在 <strong>设置 &gt; 存储与安全</strong> 中可以手动调整向量维度（128~4096）：</p><ul><li>必须与所选模型实际输出的维度一致</li><li>较小的维度节省存储和计算资源</li><li>较大的维度保留更多语义信息</li></ul><h2 id="向量化请求配置" tabindex="-1">向量化请求配置 <a class="header-anchor" href="#向量化请求配置" aria-label="Permalink to &quot;向量化请求配置&quot;">​</a></h2><p>在 <strong>设置 &gt; 向量化请求配置</strong> 中可以精细控制向量化过程：</p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>建议值</th></tr></thead><tbody><tr><td>最大并发请求数</td><td>同时发起的 API 请求数量</td><td>2-5（根据 API 限制调整）</td></tr><tr><td>单次请求批次大小</td><td>一次请求中包含的文本数量</td><td>8-16（大模型通常支持批量）</td></tr><tr><td>内容长度限制</td><td>单个条目字符上限</td><td>12000（超出会跳过）</td></tr><tr><td>请求超时</td><td>单次请求最长等待时间</td><td>60000ms</td></tr><tr><td>最大重试次数</td><td>失败后的自动重试次数</td><td>2</td></tr><tr><td>重试间隔</td><td>重试间的等待时间</td><td>3000ms</td></tr><tr><td>重试模式</td><td>固定间隔/指数退避</td><td>fixed</td></tr></tbody></table><blockquote><p>TODO: 截图 - 向量化请求配置面板</p></blockquote><h2 id="重新索引" tabindex="-1">重新索引 <a class="header-anchor" href="#重新索引" aria-label="Permalink to &quot;重新索引&quot;">​</a></h2><h3 id="何时需要重新索引" tabindex="-1">何时需要重新索引 <a class="header-anchor" href="#何时需要重新索引" aria-label="Permalink to &quot;何时需要重新索引&quot;">​</a></h3><p>以下情况建议触发重新索引：</p><ol><li><strong>更换 Embedding 模型</strong>：新模型的向量与新条目的向量在同一空间，但旧条目仍使用旧模型</li><li><strong>内容批量修改</strong>：通过外部工具直接修改了知识库文件</li><li><strong>向量文件丢失或损坏</strong>：检索引擎提示向量文件不存在</li></ol><h3 id="如何操作" tabindex="-1">如何操作 <a class="header-anchor" href="#如何操作" aria-label="Permalink to &quot;如何操作&quot;">​</a></h3><p><strong>方式一：校验向量状态</strong></p><p>在知识库设置中点击 <strong>校验向量状态</strong>，系统会检查所有条目的向量文件状态，刷新 UI 显示。</p><p><strong>方式二：全部重新索引</strong></p><p>开启自动向量化后，逐个编辑条目保存即可触发重新索引。如果需要全量重建，可以：</p><ol><li>在知识库目录中删除对应的向量目录（谨慎操作）</li><li>回到应用点击 <strong>索引全部待处理条目</strong></li></ol><p><strong>方式三：清理冗余向量</strong></p><p>如果切换过模型，磁盘上会残留旧模型的向量文件。可以使用 <strong>清理冗余向量</strong>（当前库）或 <strong>全局清理</strong>（所有库）功能一键清理。</p><blockquote><p>TODO: 截图 - 设置页面中的清理按钮</p></blockquote><h2 id="索引状态监控" tabindex="-1">索引状态监控 <a class="header-anchor" href="#索引状态监控" aria-label="Permalink to &quot;索引状态监控&quot;">​</a></h2><p>在 <strong>监控</strong> 标签页可以实时查看索引引擎的运行状态：</p><h3 id="rag-trace" tabindex="-1">RAG Trace <a class="header-anchor" href="#rag-trace" aria-label="Permalink to &quot;RAG Trace&quot;">​</a></h3><p>记录每一次检索的详细耗时分解：</p><ul><li>向量化查询耗时</li><li>后端检索耗时</li><li>结果排序耗时</li></ul><p>通过分析这些耗时数据，可以诊断性能瓶颈。</p><blockquote><p>TODO: 截图 - RAG Trace 列表，展示各阶段的耗时</p></blockquote><h3 id="index-trace" tabindex="-1">Index Trace <a class="header-anchor" href="#index-trace" aria-label="Permalink to &quot;Index Trace&quot;">​</a></h3><p>记录向量化任务的运行情况：</p><ul><li>吞吐量：单位时间处理的条目数</li><li>成功/失败条目数及失败原因</li><li>当前队列长度和预估剩余时间</li></ul><h3 id="统计视图" tabindex="-1">统计视图 <a class="header-anchor" href="#统计视图" aria-label="Permalink to &quot;统计视图&quot;">​</a></h3><p>在 <strong>统计</strong> 标签页可以查看全局索引概览：</p><table tabindex="0"><thead><tr><th>指标</th><th>说明</th></tr></thead><tbody><tr><td>总条目数</td><td>所有知识库的条目总数</td></tr><tr><td>已向量化条目</td><td>成功生成向量的条目数及百分比</td></tr><tr><td>总 Token 消耗</td><td>所有向量化操作累计消耗的 Token 数</td></tr><tr><td>全局标签池</td><td>已注册的标签总数和已向量化标签数</td></tr><tr><td>各库统计</td><td>每个知识库的独立统计数据</td></tr></tbody></table><blockquote><p>TODO: 截图 - 统计页面展示全局数据和各库详情</p></blockquote><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-搜索不到内容是怎么回事" tabindex="-1">Q：搜索不到内容是怎么回事？ <a class="header-anchor" href="#q-搜索不到内容是怎么回事" aria-label="Permalink to &quot;Q：搜索不到内容是怎么回事？&quot;">​</a></h3><ol><li><strong>检查模型一致性</strong>：当前选中的 Embedding 模型是否与向量化时一致？切换模型后旧向量不会被自动迁移</li><li><strong>点击校验向量状态</strong>：在设置中强制同步磁盘和 UI 状态</li><li><strong>检查条目状态</strong>：确认条目已经完成向量化（状态为&quot;已就绪&quot;）</li></ol><h3 id="q-向量化速度太慢怎么办" tabindex="-1">Q：向量化速度太慢怎么办？ <a class="header-anchor" href="#q-向量化速度太慢怎么办" aria-label="Permalink to &quot;Q：向量化速度太慢怎么办？&quot;">​</a></h3><ol><li>在设置中增加&quot;最大并发请求数&quot;</li><li>检查 API 服务是否存在限流</li><li>确认内容长度未超限（超长条目会重试多次）</li><li>使用轻量级的 Embedding 模型</li></ol><h3 id="q-切换-embedding-模型后需要做什么" tabindex="-1">Q：切换 Embedding 模型后需要做什么？ <a class="header-anchor" href="#q-切换-embedding-模型后需要做什么" aria-label="Permalink to &quot;Q：切换 Embedding 模型后需要做什么？&quot;">​</a></h3><p>切换模型后建议：</p><ol><li>点击 <strong>校验向量状态</strong> 确认哪些条目使用了新模型</li><li>对新模型下未向量化的条目执行批量索引</li><li>完成后在 <strong>清理冗余向量</strong> 中一键清理旧模型向量以释放磁盘空间</li></ol><h3 id="q-如何避免向量化失败" tabindex="-1">Q：如何避免向量化失败？ <a class="header-anchor" href="#q-如何避免向量化失败" aria-label="Permalink to &quot;Q：如何避免向量化失败？&quot;">​</a></h3><ul><li>确保 API 配置正确，在 LLM Chat 中测试同一模型是否正常工作</li><li>适当缩短&quot;内容长度限制&quot;防止超长内容</li><li>增加&quot;最大重试次数&quot;和&quot;请求超时&quot;以应对偶发网络问题</li><li>检查 API 账户余额和调用限额</li></ul>',73)])])}const p=a(r,[["render",i]]);export{u as __pageData,p as default};
